import React from 'react';
import './contatos.css';

export default () => {
    const [nome, setNome] = React.useState("");
    const [email, setEmail] = React.useState("");
    const [message, setMessage] = React.useState("");

    const handleSubmit = (event) => {
        event.preventDefault();
        // Aqui você pode adicionar a lógica para enviar o email
        console.log(`Email: ${email}, Message: ${message}`);
    };

    return (
        <>
            <div id='contatos' className='img'>
                <h1>Solicite um Orçamento</h1>
                <div className='form'>
                    <form onSubmit={handleSubmit}>

                        <label>
                            Nome:
                            <input type="email" placeholder='Digite seu nome' value={nome} onChange={e => setEmail(e.target.value)} required />
                        </label>

                        <label>
                            Telefone:
                            <input type="email" placeholder='Digite seu telefone com DDD' value={nome} onChange={e => setEmail(e.target.value)} required />
                        </label>

                        <label>
                            Email:
                            <input type="email" placeholder='Digite seu E-mail' value={email} onChange={e => setEmail(e.target.value)} required />
                        </label>

                        <label>
                            Message:
                            <textarea value={message} onChange={e => setMessage(e.target.value)} required />
                        </label>

                        <input type="submit" value="Enviar" />
                    </form>
                </div>
            </div>
        </>
    );
};
